/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} source
 * @param {number} target
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, source, target, k) {
    if (source === target) return 0;

    // Collect all unique edge weights to form the search space for binary search
    const uniqueWeights = new Set();
    for (const [, , w] of edges) {
        uniqueWeights.add(w);
    }
    // Include 0 as a potential threshold if it's not already there, 
    // although the minimum possible meaningful threshold based on weights is min(W) or 0.
    uniqueWeights.add(0); 

    const sortedWeights = Array.from(uniqueWeights).sort((a, b) => a - b);

    /**
     * Checks if a path exists from source to target using at most k heavy edges,
     * given a specific threshold.
     * @param {number} threshold
     * @returns {boolean}
     */
    const check = (threshold) => {
        // dist[i][j] = minimum number of heavy edges required to reach node i from source,
        // using exactly j heavy edges (this is complex).
        // A simpler approach is using BFS/Dijkstra on the state (node, heavy_edge_count).

        // dist[i][j]: minimum path cost (or just reachability) to node i using exactly j heavy edges.
        // Since we only care about reachability with <= k heavy edges, we use BFS/Dijkstra on (node, heavy_count).

        // Initialize distances: min heavy edges to reach node i with current heavy edge count j.
        // We only care about reachability, so we can use a distance array for BFS state.

        // dist[i][j] = true if node i is reachable using exactly j heavy edges.
        // Since we are finding minimum threshold, we need to check if *any* path exists with <= k heavy edges.

        // State for BFS: [node, heavy_count]
        const queue = [];
        // visited[node][heavy_count]
        const visited = Array(n).fill(0).map(() => Array(k + 1).fill(false));

        // Start state
        queue.push([source, 0]);
        visited[source][0] = true;

        let head = 0;
        while (head < queue.length) {
            const [u, heavyCount] = queue[head++];

            if (u === target) {
                return true; // Found a valid path
            }

            // Explore neighbors
            for (const [u_edge, v_edge, w] of edges) {
                let u_neighbor = -1;
                let v_neighbor = -1;

                if (u_edge === u) {
                    u_neighbor = v_edge;
                    v_neighbor = u_edge;
                } else if (v_edge === u) {
                    u_neighbor = u_edge;
                    v_neighbor = v_edge; // This is wrong, should be the other endpoint
                    // Since edges are undirected, we check both directions
                } else {
                    continue; // Not connected to u
                }

                // Re-iterate over edges to find neighbors properly for undirected graph
                for (const [u_e, v_e, w_e] of edges) {
                    let v_next = -1;
                    if (u_e === u) v_next = v_e;
                    else if (v_e === u) v_next = u_e;

                    if (v_next !== -1) {
                        const isHeavy = w_e > threshold ? 1 : 0;
                        const nextHeavyCount = heavyCount + isHeavy;

                        if (nextHeavyCount <= k && !visited[v_next][nextHeavyCount]) {
                            visited[v_next][nextHeavyCount] = true;
                            queue.push([v_next, nextHeavyCount]);
                        }
                    }
                }
            }
        }

        // Corrected neighbor iteration structure using adjacency list concept implicitly
        const adj = Array(n).fill(0).map(() => []);
        for (const [u_e, v_e, w_e] of edges) {
            adj[u_e].push({ neighbor: v_e, weight: w_e });
            adj[v_e].push({ neighbor: u_e, weight: w_e });
        }

        const q = [[source, 0]]; // [node, heavy_count]
        const vis = Array(n).fill(0).map(() => Array(k + 1).fill(false));
        vis[source][0] = true;
        let q_head = 0;

        while (q_head < q.length) {
            const [u_curr, hc_curr] = q[q_head++];

            if (u_curr === target) {
                return true;
            }

            for (const edge of adj[u_curr]) {
                const v_next = edge.neighbor;
                const w_next = edge.weight;

                const isHeavy = w_next > threshold ? 1 : 0;
                const hc_next = hc_curr + isHeavy;

                if (hc_next <= k && !vis[v_next][hc_next]) {
                    vis[v_next][hc_next] = true;
                    q.push([v_next, hc_next]);
                }
            }
        }

        return false;
    };

    // Binary Search on the sorted unique weights (plus potential values in between, but since the property 
    // (existence of path) is monotonic w.r.t. threshold, we only need to check the values present in edges).

    let low = 0; // Corresponds to the index of threshold 0 (or the smallest possible weight)
    let high = sortedWeights.length - 1;
    let result = -1;

    // We search over the indices of sortedWeights
    while (low <= high) {
        const midIndex = Math.floor((low + high) / 2);
        const currentThreshold = sortedWeights[midIndex];

        if (check(currentThreshold)) {
            // This threshold works, try for a smaller one
            result = currentThreshold;
            high = midIndex - 1;
        } else {
            // This threshold is too small, need a larger one (to classify fewer edges as heavy)
            low = midIndex + 1;
        }
    }

    // Edge case: If the smallest possible weight (sortedWeights[0] which is 0) already fails, 
    // and no larger weight works (result remains -1), we return -1.
    // If result is still -1, it means even the largest possible threshold (all edges light) failed, 
    // which implies the target is unreachable regardless of threshold.
    return result;
}

