        // Corrected neighbor iteration structure using adjacency list concept implicitly
        const adj = Array(n).fill(0).map(() => []);
        for (const [u_e, v_e, w_e] of edges) {
            adj[u_e].push({ neighbor: v_e, weight: w_e });
            adj[v_e].push({ neighbor: u_e, weight: w_e });
        }

        const q = [[source, 0]]; // [node, heavy_count]
        const vis = Array(n).fill(0).map(() => Array(k + 1).fill(false));
        vis[source][0] = true;
        let q_head = 0;

        while (q_head < q.length) {
            const [u_curr, hc_curr] = q[q_head++];

            if (u_curr === target) {
                return true;
            }

            for (const edge of adj[u_curr]) {
                const v_next = edge.neighbor;
                const w_next = edge.weight;

                const isHeavy = w_next > threshold ? 1 : 0;
                const hc_next = hc_curr + isHeavy;

                if (hc_next <= k && !vis[v_next][hc_next]) {
                    vis[v_next][hc_next] = true;
                    q.push([v_next, hc_next]);
                }
            }
        }

        return false;
    };

    // Binary Search on the sorted unique weights (plus potential values in between, but since the property 
    // (existence of path) is monotonic w.r.t. threshold, we only need to check the values present in edges).

    let low = 0; // Corresponds to the index of threshold 0 (or the smallest possible weight)
    let high = sortedWeights.length - 1;
    let result = -1;

    // We search over the indices of sortedWeights
    while (low <= high) {
        const midIndex = Math.floor((low + high) / 2);
        const currentThreshold = sortedWeights[midIndex];

        if (check(currentThreshold)) {
            // This threshold works, try for a smaller one
            result = currentThreshold;
            high = midIndex - 1;
        } else {
            // This threshold is too small, need a larger one (to classify fewer edges as heavy)
            low = midIndex + 1;
        }
    }

    // Edge case: If the smallest possible weight (sortedWeights[0] which is 0) already fails, 
    // and no larger weight works (result remains -1), we return -1.
    // If result is still -1, it means even the largest possible threshold (all edges light) failed, 
    // which implies the target is unreachable regardless of threshold.
    return result;
}
